16	
17	  constructor(config: GeneratorConfig) {
18	    this.config = config
19	  }
20	
21	  async init(): Promise<void> {
22	    await this.initImpl()
23	    this.manifest = await this.getManifest()
24	  }
25	
26	  protected abstract initImpl(): Promise<void>
27	
28	  protected abstract getManifest(): Promise<GeneratorManifest | null>
29	
30	  abstract stop(): void
31	
32	  generate(): Promise<void> {
33	    if (!this.options) {
34	      throw new Error(`Please first run .setOptions() on the Generator to initialize the options`)
35	    }
36	    return this.generateImpl(this.options)
37	  }
38	
39	  protected abstract generateImpl(options: GeneratorOptions): Promise<void>
40	
41	  setOptions(options: GeneratorOptions): void {
42	    this.options = options
43	  }
44	
