21	    if (json.method === 'generate' && json.params) {
22	      try {
23	        const result = await handler.onGenerate(json.params)
24	        respond({
25	          jsonrpc: '2.0',
26	          result: result,
27	          id: json.id,
28	        })
29	      } catch (_e) {
30	        const e = _e as Error
31	        respond({
32	          jsonrpc: '2.0',
33	          error: {
34	            code: -32000,
35	            message: e.message,
36	            data: {
37	              stack: e.stack,
38	            },
39	          },
40	          id: json.id,
41	        })
42	      }
43	    }
44	
45	    if (json.method === 'getManifest') {
46	      if (handler.onManifest) {
47	        try {
48	          const manifest = await handler.onManifest(json.params)
49	          respond({
50	            jsonrpc: '2.0',
51	            result: {
52	              manifest,
53	            },
54	            id: json.id,
55	          })
56	        } catch (_e) {
