/** Maps Prisma scalar type names to their TypeScript equivalents for REST serialization. */
const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/** Returns the TypeScript type string for a Prisma scalar type, falling back to `string`. */
export function mapScalarType(prismaType: string): string {
  return PRISMA_TO_TS_TYPE[prismaType] ?? 'string'
}

/** Wraps a type string in `Array<...>` when the field is a list. */
export function wrapList(tsType: string, isList: boolean): string {
  return isList ? `${tsType}[]` : tsType
}

/** Appends ` | null` when the field is not required. */
export function wrapNullable(tsType: string, isRequired: boolean): string {
  return isRequired ? tsType : `${tsType} | null`
}

/** Lowercases the first character of a string. */
export function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Indents every line of `text` by `depth * 2` spaces. */
export function indent(text: string, depth: number): string {
  const pad = ' '.repeat(depth * 2)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}

/** Joins an array of code blocks with double-newline separators. */
export function joinBlocks(blocks: string[]): string {
  return blocks.filter((b) => b.length > 0).join('\n\n')
}

