import type * as DMMF from '@prisma/dmmf'

import { indent, joinBlocks, lowerFirst, mapScalarType, wrapList, wrapNullable } from './template'

interface ScalarField {
  name: string
  tsType: string
  isRequired: boolean
  isList: boolean
  isId: boolean
  hasDefaultValue: boolean
  isUpdatedAt: boolean
  isGenerated: boolean
}

interface ModelInfo {
  name: string
  plural: string
  idFieldName: string
  idFieldType: string
  scalarFields: ScalarField[]
}

/**
 * Generates a typed REST API client source file from the DMMF document.
 * Returns the full content of the `rest-client.ts` output file.
 */
export function generate(dmmf: DMMF.Document): string {
  const enumNames = new Set(dmmf.datamodel.enums.map((e) => e.name))

  const models = dmmf.datamodel.models.map((model) => {
    const plural = findPlural(dmmf.mappings.modelOperations, model.name)
    const scalarFields = extractScalarFields(model, enumNames)
    const { idFieldName, idFieldType } = detectIdField(model, scalarFields)

    return { name: model.name, plural, idFieldName, idFieldType, scalarFields } satisfies ModelInfo
  })

  const blocks: string[] = [
    fileHeader(),
    generateEnums(dmmf.datamodel.enums),
    ...models.map((m) => generateModelInterface(m)),
    ...models.map((m) => generateCreateInput(m)),
    ...models.map((m) => generateUpdateInput(m)),
    ...models.map((m) => generateModelClient(m)),
    generateRestApiClient(models),
  ]

  return joinBlocks(blocks) + '\n'
}

function fileHeader(): string {
  return [
    '// -------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-client',
    '// Do not edit manually.',
    '// -------------------------------------------------',
  ].join('\n')
}

// -- Enum generation ----------------------------------------------------------

function generateEnums(enums: readonly DMMF.DatamodelEnum[]): string {
  return joinBlocks(enums.map(generateEnum))
}

function generateEnum(e: DMMF.DatamodelEnum): string {
  const members = e.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${e.name} {\n${members}\n}`
}

// -- Model interface ----------------------------------------------------------

function generateModelInterface(model: ModelInfo): string {
  const fields = model.scalarFields.map((f) => {
    const baseType = wrapList(f.tsType, f.isList)
    const fullType = wrapNullable(baseType, f.isRequired)
    return `  ${f.name}: ${fullType};`
  })
  return `export interface ${model.name} {\n${fields.join('\n')}\n}`
}

// -- CreateInput --------------------------------------------------------------

function generateCreateInput(model: ModelInfo): string {
  const fields = model.scalarFields.map((f) => {
    const isAutomatic = f.hasDefaultValue || f.isUpdatedAt || f.isGenerated
    const optional = isAutomatic ? '?' : ''
    const baseType = wrapList(f.tsType, f.isList)
    const fullType = wrapNullable(baseType, f.isRequired)
    return `  ${f.name}${optional}: ${fullType};`
  })
  return `export interface ${model.name}CreateInput {\n${fields.join('\n')}\n}`
}

// -- UpdateInput --------------------------------------------------------------

function generateUpdateInput(model: ModelInfo): string {
  const fields = model.scalarFields.map((f) => {
    const baseType = wrapList(f.tsType, f.isList)
    const fullType = wrapNullable(baseType, f.isRequired)
    return `  ${f.name}?: ${fullType};`
  })
  return `export interface ${model.name}UpdateInput {\n${fields.join('\n')}\n}`
}

// -- Per-model REST client class ----------------------------------------------

function generateModelClient(model: ModelInfo): string {
  const { name, plural, idFieldName, idFieldType } = model
  const resourcePath = lowerFirst(plural)

  const body = `
export class ${name}Client {
  #baseUrl: string;
  #headers: Record<string, string>;

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
    this.#baseUrl = baseUrl;
    this.#headers = headers;
  }

  /** Fetch all ${plural}. */
  async findMany(query?: Record<string, string>): Promise<${name}[]> {
    const qs = query ? '?' + new URLSearchParams(query).toString() : '';
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}\${qs}\`, {
      headers: this.#headers,
    });
    if (!response.ok) throw new Error(\`GET /${resourcePath} failed: \${response.status}\`);
    return response.json() as Promise<${name}[]>;
  }

  /** Fetch a single ${name} by its ID. */
  async findUnique(${idFieldName}: ${idFieldType}): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${${idFieldName}}\`, {
      headers: this.#headers,
    });
    if (!response.ok) throw new Error(\`GET /${resourcePath}/\${${idFieldName}} failed: \${response.status}\`);
    return response.json() as Promise<${name}>;
  }

  /** Create a new ${name}. */
  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error(\`POST /${resourcePath} failed: \${response.status}\`);
    return response.json() as Promise<${name}>;
  }

  /** Update an existing ${name} by its ID. */
  async update(${idFieldName}: ${idFieldType}, data: ${name}UpdateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${${idFieldName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json', ...this.#headers },
      body: JSON.stringify(data),
    });
    if (!response.ok) throw new Error(\`PATCH /${resourcePath}/\${${idFieldName}} failed: \${response.status}\`);
    return response.json() as Promise<${name}>;
  }

  /** Delete a ${name} by its ID. */
  async delete(${idFieldName}: ${idFieldType}): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${${idFieldName}}\`, {
      method: 'DELETE',
      headers: this.#headers,
    });
    if (!response.ok) throw new Error(\`DELETE /${resourcePath}/\${${idFieldName}} failed: \${response.status}\`);
    return response.json() as Promise<${name}>;
  }
}`

  return body.trim()
}

// -- Aggregated REST client ---------------------------------------------------

function generateRestApiClient(models: ModelInfo[]): string {
  const properties = models.map((m) => {
    const propName = lowerFirst(m.name)
    return `  ${propName}: ${m.name}Client;`
  })

  const assignments = models.map((m) => {
    const propName = lowerFirst(m.name)
    return `    this.${propName} = new ${m.name}Client(baseUrl, headers);`
  })

  return [
    `export class RestApiClient {`,
    ...properties,
    ``,
    `  constructor(baseUrl: string, headers: Record<string, string> = {}) {`,
    ...assignments,
    `  }`,
    `}`,
  ].join('\n')
}

// -- Helpers ------------------------------------------------------------------

function findPlural(mappings: readonly DMMF.ModelMapping[], modelName: string): string {
  const mapping = mappings.find((m) => m.model === modelName)
  return mapping?.plural ?? modelName + 's'
}

function extractScalarFields(model: DMMF.Model, enumNames: Set<string>): ScalarField[] {
  return model.fields
    .filter((f) => f.kind === 'scalar' || f.kind === 'enum')
    .map((f) => ({
      name: f.name,
      tsType: f.kind === 'enum' ? f.type : mapScalarType(f.type),
      isRequired: f.isRequired,
      isList: f.isList,
      isId: f.isId,
      hasDefaultValue: f.hasDefaultValue,
      isUpdatedAt: f.isUpdatedAt ?? false,
      isGenerated: f.isGenerated ?? false,
    }))
}

function detectIdField(
  model: DMMF.Model,
  scalarFields: ScalarField[],
): { idFieldName: string; idFieldType: string } {
  // 1. Field explicitly marked with @id
  const idField = scalarFields.find((f) => f.isId)
  if (idField) {
    return { idFieldName: idField.name, idFieldType: idField.tsType }
  }

  // 2. Composite @@id — use the first field
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const pkFieldName = model.primaryKey.fields[0]
    const pkField = scalarFields.find((f) => f.name === pkFieldName)
    if (pkField) {
      return { idFieldName: pkField.name, idFieldType: pkField.tsType }
    }
  }

  // 3. Fallback to the first @unique field
  const uniqueField = model.fields.find((f) => f.isUnique && (f.kind === 'scalar' || f.kind === 'enum'))
  if (uniqueField) {
    const tsType = uniqueField.kind === 'enum' ? uniqueField.type : mapScalarType(uniqueField.type)
    return { idFieldName: uniqueField.name, idFieldType: tsType }
  }

  // 4. Last resort — use "id" with string type
  return { idFieldName: 'id', idFieldType: 'string' }
}

