    const output = generate(dmmf)

    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('user: UserClient;')
    expect(output).toContain('post: PostClient;')
    expect(output).toContain('this.user = new UserClient(baseUrl, headers);')
    expect(output).toContain('this.post = new PostClient(baseUrl, headers);')
  })

  test('handles models without an explicit @id (falls back to @@id)', () => {
    const dmmf = createTestDmmf({
